#!/usr/bin/env node
// Stage 1D-B · Fails if any deno.lock file exists in the working tree.
// These files are generated by `deno test` / `deno check` and must not be
// committed.

import { readdirSync, statSync, existsSync } from "node:fs";
import { join, relative } from "node:path";

const ROOT = process.cwd();
const SKIP = new Set(["node_modules", ".git", "dist", "build", ".turbo", ".next", ".cache"]);
const found = [];

function walk(dir) {
  for (const name of readdirSync(dir)) {
    if (SKIP.has(name)) continue;
    const p = join(dir, name);
    let st;
    try { st = statSync(p); } catch { continue; }
    if (st.isDirectory()) walk(p);
    else if (st.isFile() && name === "deno.lock") found.push(relative(ROOT, p));
  }
}

if (existsSync(ROOT)) walk(ROOT);

if (found.length > 0) {
  console.error("[check-no-deno-locks] generated lock files present:");
  for (const f of found) console.error(`  ${f}`);
  console.error("Delete them before committing (they are not tracked).");
  process.exit(1);
}
console.log("[check-no-deno-locks] OK (no deno.lock files).");
